import { useMemo } from 'react';
import { Card, Stack, Row, Text, Box } from '@ggui-ai/design/primitives';

interface ForecastItem {
  day: string;
  condition: string;
  high: number;
  low: number;
}

interface Props {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit: string;
  forecast: ForecastItem[];
}

const getWeatherEmoji = (condition: string): string => {
  const conditionLower = condition.toLowerCase();
  if (conditionLower.includes('sun') || conditionLower.includes('clear')) return '☀️';
  if (conditionLower.includes('cloud')) return '☁️';
  if (conditionLower.includes('rain')) return '🌧️';
  if (conditionLower.includes('snow')) return '❄️';
  if (conditionLower.includes('wind')) return '💨';
  if (conditionLower.includes('thunder') || conditionLower.includes('storm')) return '⛈️';
  if (conditionLower.includes('mist') || conditionLower.includes('fog')) return '🌫️';
  return '🌤️';
};

export default function WeatherCard({
  city = 'Unknown City',
  temperature = 0,
  condition = 'Clear',
  humidity = 0,
  windSpeed = 0,
  unit = '°C',
  forecast = [],
}: Props) {
  const weatherEmoji = useMemo(() => getWeatherEmoji(condition), [condition]);

  return (
    <Card
      padding={24}
      shadow="md"
      style={{
        background: `linear-gradient(135deg, var(--ggui-color-primary-50, #f0f9ff), var(--ggui-color-primary-100, #e0f2fe))`,
      }}
    >
      <Stack direction="vertical" gap={24}>
        {/* Header with City Name */}
        <Box>
          <Text variant="h2" color="var(--ggui-color-primary-900, #0c4a6e)">
            {city}
          </Text>
        </Box>

        {/* Current Weather Section */}
        <Stack direction="vertical" gap={16}>
          {/* Temperature and Condition */}
          <Row align="center" gap={16}>
            <div style={{ fontSize: '72px' }}>{weatherEmoji}</div>
            <Stack direction="vertical" gap={8} align="start">
              <div style={{
                fontSize: 'var(--ggui-font-size-4xl, 36px)',
                fontWeight: 'var(--ggui-font-weight-bold, 700)',
                color: 'var(--ggui-color-primary-900, #0c4a6e)',
                lineHeight: '1',
              }}>
                {Math.round(temperature)}{unit}
              </div>
              <Text
                variant="body"
                color="var(--ggui-color-primary-700, #0369a1)"
                weight="semibold"
              >
                {condition}
              </Text>
            </Stack>
          </Row>

          {/* Divider */}
          <div
            style={{
              height: '1px',
              background: 'var(--ggui-color-primary-200, #bae6fd)',
              margin: 'var(--ggui-spacing-2, 8px) 0',
            }}
          />

          {/* Humidity and Wind */}
          <Row gap={24} justify="between">
            <Stack direction="vertical" gap={6}>
              <Text
                variant="caption"
                color="var(--ggui-color-primary-600, #0284c7)"
                weight="medium"
              >
                Humidity
              </Text>
              <Text
                variant="h3"
                color="var(--ggui-color-primary-900, #0c4a6e)"
              >
                {humidity}%
              </Text>
            </Stack>
            <Stack direction="vertical" gap={6}>
              <Text
                variant="caption"
                color="var(--ggui-color-primary-600, #0284c7)"
                weight="medium"
              >
                Wind Speed
              </Text>
              <Text
                variant="h3"
                color="var(--ggui-color-primary-900, #0c4a6e)"
              >
                {windSpeed} m/s
              </Text>
            </Stack>
          </Row>
        </Stack>

        {/* Forecast Section */}
        {forecast.length > 0 && (
          <Stack direction="vertical" gap={12}>
            <Text
              variant="label"
              color="var(--ggui-color-primary-600, #0284c7)"
              weight="semibold"
            >
              5-Day Forecast
            </Text>

            {/* Forecast Strip */}
            <Row gap={12} wrap style={{ justifyContent: 'space-between' }}>
              {forecast.slice(0, 5).map((item, idx) => (
                <Box
                  key={idx}
                  padding={12}
                  borderRadius="var(--ggui-shape-radius-md, 8px)"
                  style={{
                    background: 'rgba(255, 255, 255, 0.6)',
                    border: '1px solid var(--ggui-color-primary-200, #bae6fd)',
                    flex: '1',
                    minWidth: '80px',
                    textAlign: 'center',
                  }}
                >
                  <Stack direction="vertical" gap={8} align="center">
                    <Text
                      variant="label"
                      color="var(--ggui-color-primary-700, #0369a1)"
                      weight="medium"
                    >
                      {item.day}
                    </Text>
                    <div style={{ fontSize: '28px' }}>
                      {getWeatherEmoji(item.condition)}
                    </div>
                    <Stack direction="horizontal" gap={6} justify="center">
                      <Text
                        variant="caption"
                        color="var(--ggui-color-primary-900, #0c4a6e)"
                        weight="semibold"
                      >
                        {Math.round(item.high)}{unit.replace(/[^A-Z]/g, '')}
                      </Text>
                      <Text
                        variant="caption"
                        color="var(--ggui-color-primary-500, #0ea5e9)"
                      >
                        {Math.round(item.low)}{unit.replace(/[^A-Z]/g, '')}
                      </Text>
                    </Stack>
                  </Stack>
                </Box>
              ))}
            </Row>
          </Stack>
        )}
      </Stack>
    </Card>
  );
}

import React from 'react';
import { Card, Stack, Text } from '@ggui-ai/design/primitives';

interface ForecastDay {
  day: string;
  icon: string;
  high: number;
  low: number;
}

interface Props {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit: string;
  forecast: ForecastDay[];
}

const getWeatherEmoji = (condition: string): string => {
  const conditionLower = condition.toLowerCase();
  if (conditionLower.includes('sunny') || conditionLower.includes('clear')) return '☀️';
  if (conditionLower.includes('cloud')) return '☁️';
  if (conditionLower.includes('rain')) return '🌧️';
  if (conditionLower.includes('snow')) return '❄️';
  if (conditionLower.includes('storm') || conditionLower.includes('thunder')) return '⛈️';
  if (conditionLower.includes('fog') || conditionLower.includes('mist')) return '🌫️';
  if (conditionLower.includes('wind')) return '💨';
  return '🌤️';
};

export default function GeneratedComponent(props: Props = {
  city: 'San Francisco',
  temperature: 72,
  condition: 'Sunny',
  humidity: 65,
  windSpeed: 12,
  unit: 'F',
  forecast: [
    { day: 'Mon', icon: '☀️', high: 75, low: 62 },
    { day: 'Tue', icon: '☁️', high: 70, low: 58 },
    { day: 'Wed', icon: '🌧️', high: 65, low: 55 },
    { day: 'Thu', icon: '☁️', high: 68, low: 56 },
    { day: 'Fri', icon: '☀️', high: 76, low: 63 },
  ],
}) {
  const {
    city,
    temperature,
    condition,
    humidity,
    windSpeed,
    unit,
    forecast,
  } = props;

  const weatherEmoji = getWeatherEmoji(condition);

  return (
    <Card
      variant="elevated"
      style={{
        padding: 'var(--ggui-spacing-lg, 24px)',
        background: 'var(--ggui-color-surface, #fff)',
      }}
    >
      <Stack direction="vertical" gap="var(--ggui-spacing-md, 16px)">
        {/* Header with city name */}
        <Text
          variant="headline"
          size="lg"
          style={{
            color: 'var(--ggui-color-on-surface, #000)',
          }}
        >
          {city}
        </Text>

        {/* Current weather section */}
        <Stack direction="horizontal" gap="var(--ggui-spacing-lg, 24px)" style={{ alignItems: 'center' }}>
          {/* Temperature display */}
          <Stack direction="vertical" gap="var(--ggui-spacing-sm, 8px)">
            <Text
              style={{
                fontSize: '4rem',
                fontWeight: '300',
                color: 'var(--ggui-color-primary, #1976d2)',
                lineHeight: '1',
              }}
            >
              {temperature}°{unit}
            </Text>
            <Text
              style={{
                color: 'var(--ggui-color-on-surface-variant, #666)',
              }}
            >
              {condition}
            </Text>
          </Stack>

          {/* Weather emoji icon */}
          <Text
            style={{
              fontSize: '5rem',
              lineHeight: '1',
            }}
          >
            {weatherEmoji}
          </Text>
        </Stack>

        {/* Humidity and Wind Speed */}
        <Stack direction="horizontal" gap="var(--ggui-spacing-md, 16px)">
          <Stack
            direction="vertical"
            gap="var(--ggui-spacing-xs, 4px)"
            style={{
              flex: 1,
              padding: 'var(--ggui-spacing-md, 16px)',
              background: 'var(--ggui-color-surface-variant, #f5f5f5)',
              borderRadius: 'var(--ggui-border-radius-md, 8px)',
            }}
          >
            <Text
              style={{
                color: 'var(--ggui-color-on-surface-variant, #666)',
                textTransform: 'uppercase',
                letterSpacing: '0.5px',
                fontSize: '0.75rem',
              }}
            >
              Humidity
            </Text>
            <Text
              style={{
                color: 'var(--ggui-color-on-surface, #000)',
                fontWeight: '600',
              }}
            >
              {humidity}%
            </Text>
          </Stack>

          <Stack
            direction="vertical"
            gap="var(--ggui-spacing-xs, 4px)"
            style={{
              flex: 1,
              padding: 'var(--ggui-spacing-md, 16px)',
              background: 'var(--ggui-color-surface-variant, #f5f5f5)',
              borderRadius: 'var(--ggui-border-radius-md, 8px)',
            }}
          >
            <Text
              style={{
                color: 'var(--ggui-color-on-surface-variant, #666)',
                textTransform: 'uppercase',
                letterSpacing: '0.5px',
                fontSize: '0.75rem',
              }}
            >
              Wind Speed
            </Text>
            <Text
              style={{
                color: 'var(--ggui-color-on-surface, #000)',
                fontWeight: '600',
              }}
            >
              {windSpeed} {unit === 'F' ? 'mph' : 'km/h'}
            </Text>
          </Stack>
        </Stack>

        {/* 5-day forecast strip */}
        {forecast && forecast.length > 0 && (
          <Stack
            direction="vertical"
            gap="var(--ggui-spacing-md, 16px)"
            style={{
              marginTop: 'var(--ggui-spacing-md, 16px)',
              paddingTop: 'var(--ggui-spacing-md, 16px)',
              borderTop: '1px solid var(--ggui-color-outline, #e0e0e0)',
            }}
          >
            <Text
              style={{
                color: 'var(--ggui-color-on-surface-variant, #666)',
                fontWeight: '600',
                fontSize: '0.875rem',
              }}
            >
              5-Day Forecast
            </Text>
            <Stack
              direction="horizontal"
              gap="var(--ggui-spacing-sm, 8px)"
              style={{
                overflowX: 'auto',
                paddingBottom: 'var(--ggui-spacing-xs, 4px)',
              }}
            >
              {forecast.map((day, index) => (
                <Stack
                  key={index}
                  direction="vertical"
                  gap="var(--ggui-spacing-xs, 4px)"
                  style={{
                    minWidth: '80px',
                    padding: 'var(--ggui-spacing-md, 16px)',
                    background: 'var(--ggui-color-surface-variant, #f5f5f5)',
                    borderRadius: 'var(--ggui-border-radius-md, 8px)',
                    textAlign: 'center',
                    transition: 'all 0.2s ease-in-out',
                    cursor: 'pointer',
                  }}
                  onMouseEnter={(e) => {
                    const elem = e.currentTarget;
                    elem.style.background = 'var(--ggui-color-primary-container, #e3f2fd)';
                    elem.style.transform = 'translateY(-2px)';
                  }}
                  onMouseLeave={(e) => {
                    const elem = e.currentTarget;
                    elem.style.background = 'var(--ggui-color-surface-variant, #f5f5f5)';
                    elem.style.transform = 'translateY(0)';
                  }}
                >
                  <Text
                    style={{
                      color: 'var(--ggui-color-on-surface-variant, #666)',
                      fontWeight: '500',
                      fontSize: '0.75rem',
                    }}
                  >
                    {day.day}
                  </Text>
                  <Text
                    style={{
                      fontSize: '1.75rem',
                      lineHeight: '1',
                    }}
                  >
                    {day.icon}
                  </Text>
                  <Stack direction="vertical" gap="var(--ggui-spacing-xs, 4px)">
                    <Text
                      style={{
                        color: 'var(--ggui-color-on-surface, #000)',
                        fontWeight: '600',
                        fontSize: '0.75rem',
                      }}
                    >
                      {day.high}°
                    </Text>
                    <Text
                      style={{
                        color: 'var(--ggui-color-on-surface-variant, #666)',
                        fontSize: '0.65rem',
                      }}
                    >
                      {day.low}°
                    </Text>
                  </Stack>
                </Stack>
              ))}
            </Stack>
          </Stack>
        )}
      </Stack>
    </Card>
  );
}

import { Stack, Row, Text, Card } from '@ggui-ai/design/primitives';

interface ForecastDay {
  day: string;
  icon: string;
  high: number;
  low: number;
}

interface Props {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit: string;
  forecast: ForecastDay[];
}

const weatherEmojis: Record<string, string> = {
  sunny: '☀️',
  cloudy: '☁️',
  rainy: '🌧️',
  snowy: '❄️',
  partly_cloudy: '⛅',
  windy: '💨',
  foggy: '🌫️',
  thunderstorm: '⛈️',
};

export default function GeneratedComponent({
  city = 'New York',
  temperature = 72,
  condition = 'sunny',
  humidity = 65,
  windSpeed = 10,
  unit = '°F',
  forecast = [
    { day: 'Mon', icon: 'sunny', high: 75, low: 62 },
    { day: 'Tue', icon: 'partly_cloudy', high: 73, low: 61 },
    { day: 'Wed', icon: 'rainy', high: 68, low: 58 },
    { day: 'Thu', icon: 'sunny', high: 76, low: 63 },
    { day: 'Fri', icon: 'cloudy', high: 70, low: 59 },
  ],
}: Props) {
  const getWeatherEmoji = (cond: string) => weatherEmojis[cond.toLowerCase()] || '🌡️';

  return (
    <Card padding={0} shadow="none" border={false}>
      <Stack direction="vertical" gap={0} align="stretch">
        {/* Header with city name */}
        <div style={{
          padding: 'var(--ggui-spacing-4)',
          borderBottom: '1px solid var(--ggui-color-neutral-200)',
        }}>
          <Text variant="label" color="var(--ggui-color-neutral-500)">
            {city}
          </Text>
        </div>

        {/* Current weather section */}
        <div style={{
          padding: 'var(--ggui-spacing-4)',
          display: 'flex',
          flexDirection: 'column',
          gap: 'var(--ggui-spacing-4)',
        }}>
          {/* Temperature and condition */}
          <div style={{
            display: 'flex',
            alignItems: 'center',
            gap: 'var(--ggui-spacing-4)',
          }}>
            <div style={{
              fontSize: '48px',
              lineHeight: 1,
            }}>
              {getWeatherEmoji(condition)}
            </div>
            <div>
              <div style={{
                fontSize: 'var(--ggui-font-size-4xl)',
                fontWeight: 'var(--ggui-font-weight-bold)',
                color: 'var(--ggui-color-neutral-900)',
                lineHeight: 1.2,
              }}>
                {temperature}{unit}
              </div>
              <Text variant="body" color="var(--ggui-color-neutral-500)" weight="medium">
                {condition.replace(/_/g, ' ').charAt(0).toUpperCase() + condition.replace(/_/g, ' ').slice(1)}
              </Text>
            </div>
          </div>

          {/* Humidity and wind speed */}
          <Row gap={16} justify="start" align="stretch">
            <div style={{
              flex: 1,
              padding: 'var(--ggui-spacing-2)',
              backgroundColor: 'var(--ggui-color-neutral-50)',
              borderRadius: 'var(--ggui-shape-radius-md)',
              textAlign: 'center',
            }}>
              <Text variant="caption" color="var(--ggui-color-neutral-500)" weight="medium">
                Humidity
              </Text>
              <div style={{
                fontSize: 'var(--ggui-font-size-lg)',
                fontWeight: 'var(--ggui-font-weight-semibold)',
                color: 'var(--ggui-color-neutral-900)',
                marginTop: 'var(--ggui-spacing-1)',
              }}>
                {humidity}%
              </div>
            </div>
            <div style={{
              flex: 1,
              padding: 'var(--ggui-spacing-2)',
              backgroundColor: 'var(--ggui-color-neutral-50)',
              borderRadius: 'var(--ggui-shape-radius-md)',
              textAlign: 'center',
            }}>
              <Text variant="caption" color="var(--ggui-color-neutral-500)" weight="medium">
                Wind
              </Text>
              <div style={{
                fontSize: 'var(--ggui-font-size-lg)',
                fontWeight: 'var(--ggui-font-weight-semibold)',
                color: 'var(--ggui-color-neutral-900)',
                marginTop: 'var(--ggui-spacing-1)',
              }}>
                {windSpeed} mph
              </div>
            </div>
          </Row>
        </div>

        {/* 5-day forecast */}
        <div style={{
          borderTop: '1px solid var(--ggui-color-neutral-200)',
          padding: 'var(--ggui-spacing-4)',
        }}>
          <Text variant="label" color="var(--ggui-color-neutral-700)" weight="semibold" style={{ display: 'block', marginBottom: 'var(--ggui-spacing-3)' }}>
            5-Day Forecast
          </Text>
          <div style={{
            display: 'flex',
            gap: 'var(--ggui-spacing-2)',
            overflowX: 'auto',
            paddingBottom: 'var(--ggui-spacing-2)',
          }}>
            {forecast.map((day, idx) => (
              <div
                key={idx}
                style={{
                  minWidth: '70px',
                  flex: '0 0 70px',
                  padding: 'var(--ggui-spacing-2)',
                  backgroundColor: 'var(--ggui-color-primary-50)',
                  borderRadius: 'var(--ggui-shape-radius-md)',
                  border: '1px solid var(--ggui-color-primary-200)',
                  textAlign: 'center',
                  display: 'flex',
                  flexDirection: 'column',
                  gap: 'var(--ggui-spacing-1)',
                  justifyContent: 'center',
                }}
              >
                <Text variant="caption" weight="semibold" color="var(--ggui-color-primary-700)">
                  {day.day}
                </Text>
                <div style={{ fontSize: '24px', lineHeight: 1 }}>
                  {getWeatherEmoji(day.icon)}
                </div>
                <Text variant="caption" color="var(--ggui-color-neutral-700)">
                  <span style={{ fontWeight: 'var(--ggui-font-weight-semibold)' }}>{day.high}</span>° / <span style={{ opacity: 0.7 }}>{day.low}°</span>
                </Text>
              </div>
            ))}
          </div>
        </div>
      </Stack>
    </Card>
  );
}

import React from 'react';
import {
  Card,
  Stack,
  Row,
  Text,
  Divider,
  Box,
} from '@ggui-ai/design/primitives';

interface ForecastDay {
  day: string;
  icon: string;
  high: number;
  low: number;
}

interface Props {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit: string;
  forecast: ForecastDay[];
}

const getWeatherEmoji = (condition: string): string => {
  const conditionLower = condition.toLowerCase();
  if (
    conditionLower.includes('sunny') ||
    conditionLower.includes('clear') ||
    conditionLower.includes('bright')
  ) {
    return '☀️';
  }
  if (
    conditionLower.includes('cloudy') ||
    conditionLower.includes('overcast')
  ) {
    return '☁️';
  }
  if (
    conditionLower.includes('rainy') ||
    conditionLower.includes('rain') ||
    conditionLower.includes('drizzle')
  ) {
    return '🌧️';
  }
  if (
    conditionLower.includes('stormy') ||
    conditionLower.includes('thunder') ||
    conditionLower.includes('lightning')
  ) {
    return '⛈️';
  }
  if (conditionLower.includes('snow')) {
    return '❄️';
  }
  if (conditionLower.includes('wind')) {
    return '💨';
  }
  if (conditionLower.includes('fog') || conditionLower.includes('mist')) {
    return '🌫️';
  }
  return '🌤️'; // default partly cloudy
};

export default function GeneratedComponent({
  city = 'San Francisco',
  temperature = 72,
  condition = 'Partly Cloudy',
  humidity = 65,
  windSpeed = 12,
  unit = '°F',
  forecast = [
    { day: 'Mon', icon: '☀️', high: 75, low: 62 },
    { day: 'Tue', icon: '☁️', high: 68, low: 59 },
    { day: 'Wed', icon: '🌧️', high: 64, low: 56 },
    { day: 'Thu', icon: '☀️', high: 70, low: 60 },
    { day: 'Fri', icon: '⛅', high: 73, low: 61 },
  ],
}: Props) {
  const weatherEmoji = getWeatherEmoji(condition);

  return (
    <Box
      style={{
        width: '100vw',
        height: '100dvh',
        backgroundColor: 'var(--ggui-color-neutral-50, #f9fafb)',
        padding: 'var(--ggui-spacing-6, 24px)',
        overflowY: 'auto',
        display: 'flex',
        flexDirection: 'column',
      }}
    >
      {/* Main Weather Card */}
      <Card
        shadow="md"
        padding={24}
        style={{
          background: `linear-gradient(135deg, var(--ggui-color-primary-400, #38bdf8), var(--ggui-color-primary-600, #0284c7))`,
        }}
      >
        <Stack direction="vertical" gap={16} align="center">
          {/* City Name */}
          <Text
            variant="h3"
            color="white"
            align="center"
            weight="semibold"
          >
            {city}
          </Text>

          {/* Weather Icon and Temperature */}
          <Stack direction="horizontal" gap={16} align="center" justify="center">
            <div
              style={{
                fontSize: '64px',
                lineHeight: '1',
              }}
            >
              {weatherEmoji}
            </div>
            <Text
              variant="h1"
              color="white"
              weight="bold"
              style={{
                fontSize: 'var(--ggui-font-size-4xl, 36px)',
                lineHeight: '1',
              }}
            >
              {temperature}{unit}
            </Text>
          </Stack>

          {/* Weather Condition */}
          <Text
            variant="body"
            color="white"
            align="center"
            style={{
              opacity: 0.95,
            }}
          >
            {condition}
          </Text>

          {/* Divider */}
          <Divider
            style={{
              backgroundColor: 'rgba(255, 255, 255, 0.3)',
              margin: 'var(--ggui-spacing-2, 8px) 0',
            }}
          />

          {/* Humidity and Wind Speed */}
          <Row gap={32} justify="center" align="center" style={{ width: '100%' }}>
            <Stack direction="vertical" gap={8} align="center">
              <Text
                variant="caption"
                color="white"
                style={{
                  opacity: 0.9,
                }}
              >
                💧 Humidity
              </Text>
              <Text
                variant="h3"
                color="white"
                weight="bold"
              >
                {humidity}%
              </Text>
            </Stack>

