  const cond = condition.toLowerCase();
  if (cond.includes('sunny') || cond.includes('clear')) return '☀️';
  if (cond.includes('cloudy') || cond.includes('overcast')) return '☁️';
  if (cond.includes('rainy') || cond.includes('rain')) return '🌧️';
  if (cond.includes('snowy') || cond.includes('snow')) return '❄️';
  if (cond.includes('stormy') || cond.includes('thunder')) return '⛈️';
  if (cond.includes('windy') || cond.includes('wind')) return '💨';
  if (cond.includes('foggy') || cond.includes('fog')) return '🌫️';
  if (cond.includes('partly')) return '⛅';
  return '🌤️'; // default
};

