import React from 'react'
import { Card, Stack, Text } from '@ggui-ai/design/primitives'

interface Props {
  city: string
  temperature: number
  condition: string
  humidity: number
  windSpeed: number
  unit: string
  forecast: object[]
}

type ForecastEntry = {
  day?: string
  condition?: string
  icon?: string
  high?: number
  low?: number
}

const isFiniteNumber = (value: unknown): value is number =>
  typeof value === 'number' && Number.isFinite(value)

const clamp = (value: number, min: number, max: number): number =>
  Math.min(max, Math.max(min, value))

const conditionToEmoji = (conditionRaw: string): string => {
  const normalized = conditionRaw.trim().toLowerCase()
  if (normalized.includes('sun') || normalized.includes('clear')) return '☀️'
  if (normalized.includes('cloud') || normalized.includes('overcast')) return '☁️'
  if (normalized.includes('rain') || normalized.includes('drizzle') || normalized.includes('shower')) return '🌧️'
  if (normalized.includes('storm') || normalized.includes('thunder')) return '⛈️'
  if (normalized.includes('snow') || normalized.includes('sleet') || normalized.includes('blizzard')) return '❄️'
  if (normalized.includes('fog') || normalized.includes('mist') || normalized.includes('haze')) return '🌫️'
  if (normalized.includes('wind')) return '💨'
  return '🌤️'
}

const isSunnyLike = (conditionRaw: string): boolean => {
  const normalized = conditionRaw.trim().toLowerCase()
  return normalized.includes('sun') || normalized.includes('clear')
}

export default function GeneratedComponent({
  city = '',
  temperature = Number.NaN,
  condition = '',
  humidity = Number.NaN,
  windSpeed = Number.NaN,
  unit = '',
  forecast = [],
}: Props) {
  const safeTemp = isFiniteNumber(temperature) ? String(temperature) : '—'
  const safeHumidity = isFiniteNumber(humidity) ? String(clamp(humidity, 0, 100)) + '%' : '—'
  const safeWind = isFiniteNumber(windSpeed) ? String(windSpeed) + ' ' + unit : '—'

  const icon = conditionToEmoji(condition)
  const iconColor = isSunnyLike(condition)
    ? 'var(--ggui-color-warning-500, #f59e0b)'
    : 'var(--ggui-color-primary-600, #0284c7)'

  const tempAria = isFiniteNumber(temperature)
    ? String(temperature) + ' degrees ' + unit
    : 'Temperature unavailable'

  const items = Array.isArray(forecast) ? forecast.slice(0, 5) : []

  return (
    <Card
      padding={24}
      shadow="md"
      border
      role="region"
      aria-label={'Weather in ' + city}
      style={{
        background: 'var(--ggui-color-neutral-50, #f9fafb)',
        borderColor: 'var(--ggui-color-primary-200, #bae6fd)',
        borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
        boxShadow: 'var(--ggui-shape-shadow-md)',
        transition: 'color 160ms ease, background-color 160ms ease, border-color 160ms ease',
      }}
    >
      <Stack direction="vertical" gap={16} style={{ gap: 'var(--ggui-spacing-4, 16px)' }}>
        <Stack direction="horizontal" justify="between" align="start" gap={8}>
          <Stack direction="vertical" gap={4}>
            <Text variant="h3" weight="semibold" style={{ color: 'var(--ggui-color-primary-900, #0c4a6e)' }}>
              {city}
            </Text>
            <Text variant="body" weight="medium" style={{ color: 'var(--ggui-color-primary-700, #0369a1)' }}>
              {condition}
            </Text>
          </Stack>
          <Text variant="h2" aria-label={'Condition icon ' + icon} style={{ color: iconColor }}>
            {icon}
          </Text>
        </Stack>

        <Stack direction="horizontal" align="center" gap={8}>
          <Text
            variant="h1"
            weight="bold"
            aria-label={tempAria}
            style={{ color: 'var(--ggui-color-primary-600, #0284c7)' }}
          >
            {safeTemp}
          </Text>
          <Text variant="h3" weight="medium" style={{ color: 'var(--ggui-color-primary-700, #0369a1)' }}>
            {unit}
          </Text>
        </Stack>

        <Stack
          direction="horizontal"
          aria-hidden="true"
          style={{ width: '100%', borderTop: '1px solid var(--ggui-color-primary-200, #bae6fd)', margin: 0 }}
        />

        <Stack direction="horizontal" justify="between" align="center" gap={12} wrap>
          <Card
            padding={12}
            shadow="none"
            border
            style={{
              background: 'var(--ggui-color-primary-50, #f0f9ff)',
              borderColor: 'var(--ggui-color-primary-200, #bae6fd)',
              flex: '1 1 180px',
            }}
          >
            <Stack direction="vertical" gap={4} align="center">
              <Text variant="caption" style={{ color: 'var(--ggui-color-neutral-500, #6b7280)' }}>
                Humidity
              </Text>
              <Text variant="body" weight="semibold" style={{ color: 'var(--ggui-color-neutral-900, #111827)' }}>
                {safeHumidity}
              </Text>
            </Stack>
          </Card>

          <Card
            padding={12}
            shadow="none"
            border
            style={{
              background: 'var(--ggui-color-primary-50, #f0f9ff)',
              borderColor: 'var(--ggui-color-primary-200, #bae6fd)',
              flex: '1 1 180px',
            }}
          >
            <Stack direction="vertical" gap={4} align="center">
              <Text variant="caption" style={{ color: 'var(--ggui-color-neutral-500, #6b7280)' }}>
                Wind
              </Text>
              <Text variant="body" weight="semibold" style={{ color: 'var(--ggui-color-neutral-900, #111827)' }}>
                {safeWind}
              </Text>
            </Stack>
          </Card>
        </Stack>

        <Stack
          direction="horizontal"
          aria-hidden="true"
          style={{ width: '100%', borderTop: '1px solid var(--ggui-color-primary-200, #bae6fd)', margin: 0 }}
        />

        <Stack direction="vertical" gap={8} style={{ gap: 'var(--ggui-spacing-2, 8px)' }}>
          <Text variant="label" weight="medium">
            5-Day Forecast
          </Text>

          <Stack
            direction="horizontal"
            gap={8}
            justify="between"
            align="stretch"
            wrap
            role="list"
            style={{
              rowGap: 'var(--ggui-spacing-2, 8px)',
              columnGap: 'var(--ggui-spacing-2, 8px)',
            }}
          >
            {items.map((entry, idx) => {
              const f = (entry as ForecastEntry) || {}
              const day = typeof f.day === 'string' && f.day.trim() ? f.day : '—'
              const cond = typeof f.condition === 'string' ? f.condition : ''
              const dayIcon = typeof f.icon === 'string' && f.icon.trim() ? f.icon : conditionToEmoji(cond)
              const high = isFiniteNumber(f.high) ? String(f.high) : '—'
              const low = isFiniteNumber(f.low) ? String(f.low) : '—'
              const aria = day + ', ' + (cond || 'unknown') + ', high ' + high + ', low ' + low

              return (
                <Card
                  key={day + '-' + String(idx)}
                  padding={8}
                  shadow="none"
                  border
                  role="listitem"
                  aria-label={aria}
                  style={{
                    background: 'var(--ggui-color-neutral-50, #f9fafb)',
                    borderColor: 'var(--ggui-color-neutral-200, #e5e7eb)',
                    flex: '1 1 100px',
                    minWidth: '100px',
                  }}
                >
                  <Stack direction="vertical" gap={4} align="center">
                    <Text
                      variant="caption"
                      weight="medium"
                      style={{ color: 'var(--ggui-color-neutral-700, #374151)' }}
                    >
                      {day}
                    </Text>
                    <Text variant="body">{dayIcon}</Text>
                    <Stack direction="horizontal" gap={4} justify="center">
                      <Text
                        variant="caption"
                        weight="semibold"
                        style={{ color: 'var(--ggui-color-primary-700, #0369a1)' }}
                      >
                        {high}
                      </Text>
                      <Text variant="caption">/</Text>
                      <Text variant="caption" style={{ color: 'var(--ggui-color-neutral-500, #6b7280)' }}>
                        {low}
                      </Text>
                    </Stack>
                  </Stack>
                </Card>
              )
            })}
          </Stack>
        </Stack>
      </Stack>
    </Card>
  )
}

import React from 'react';
import { Card, Stack, Row, Text, Box } from '@ggui-ai/design/primitives';

interface ForecastDay {
  day: string;
  icon: string;
  high: number;
  low: number;
}

interface Props {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit: string;
  forecast: ForecastDay[];
}

const getWeatherEmoji = (condition: string) => {
  const cond = condition.toLowerCase();
  if (cond.includes('sun') || cond.includes('clear')) return '☀️';
  if (cond.includes('partly')) return '⛅';
  if (cond.includes('cloud')) return '☁️';
  if (cond.includes('rain') || cond.includes('drizzle') || cond.includes('shower')) return '🌧️';
  if (cond.includes('storm') || cond.includes('thunder')) return '⛈️';
  if (cond.includes('snow') || cond.includes('ice')) return '❄️';
  if (cond.includes('mist') || cond.includes('fog') || cond.includes('haze')) return '🌫️';
  return '🌡️';
};

export default function WeatherCard({
  city = 'San Francisco',
  temperature = 72,
  condition = 'Sunny',
  humidity = 45,
  windSpeed = 8,
  unit = '°F',
  forecast = [
    { day: 'Mon', icon: '☀️', high: 75, low: 58 },
    { day: 'Tue', icon: '☀️', high: 78, low: 60 },
    { day: 'Wed', icon: '⛅', high: 74, low: 59 },
    { day: 'Thu', icon: '☁️', high: 70, low: 57 },
    { day: 'Fri', icon: '🌧️', high: 65, low: 55 },
  ]
}: Props) {
  const emoji = getWeatherEmoji(condition);

  return (
    <Box padding="var(--ggui-spacing-4, 16px)">
      <Card shadow="lg" padding={0} border={true}>
        <Stack direction="vertical" gap={0}>
          {/* Main Weather Section */}
          <Box 
            padding="var(--ggui-spacing-6, 24px)"
            style={{ 
              background: 'linear-gradient(135deg, var(--ggui-color-primary-50, #f0f9ff), var(--ggui-color-primary-100, #e0f2fe))',
              borderBottom: '1px solid var(--ggui-color-neutral-200, #e5e7eb)'
            }}
          >
            <Stack direction="vertical" gap={16}>
              <Row justify="between" align="center">
                <Stack direction="vertical" gap={2}>
                  <Text variant="h2" weight="bold" color="var(--ggui-color-neutral-900, #111827)">
                    {city}
                  </Text>
                  <Text variant="body" color="var(--ggui-color-neutral-500, #6b7280)">
                    {condition}
                  </Text>
                </Stack>
                <Text style={{ fontSize: '48px' }}>{emoji}</Text>
              </Row>

              <Row align="end" gap={4}>
                <Text 
                  style={{ 
                    fontSize: '64px', 
                    fontWeight: 'var(--ggui-font-weight-bold, 700)',
                    lineHeight: 1,
                    color: 'var(--ggui-color-primary-600, #0284c7)'
                  }}
                >
                  {Math.round(temperature)}
                </Text>
                <Text 
                  variant="h3" 
                  color="var(--ggui-color-primary-400, #38bdf8)"
                  style={{ marginBottom: '8px' }}
                >
                  {unit}
                </Text>
              </Row>

              <Row gap={24}>
                <Stack direction="vertical" gap={2}>
                  <Text variant="caption" weight="medium" color="var(--ggui-color-neutral-500, #6b7280)">
                    HUMIDITY
                  </Text>
                  <Text variant="body" weight="semibold" color="var(--ggui-color-neutral-900, #111827)">
                    {humidity}%
                  </Text>
                </Stack>
                <Stack direction="vertical" gap={2}>
                  <Text variant="caption" weight="medium" color="var(--ggui-color-neutral-500, #6b7280)">
                    WIND
                  </Text>
                  <Text variant="body" weight="semibold" color="var(--ggui-color-neutral-900, #111827)">
                    {windSpeed} mph
                  </Text>
                </Stack>
              </Row>
            </Stack>
          </Box>

          {/* Forecast Strip */}
          <Box padding="var(--ggui-spacing-4, 16px)">
            <Row justify="between" gap={8} wrap>
              {forecast && forecast.slice(0, 5).map((day, index) => (
                <Stack 
                  key={day.day + index} 
                  direction="vertical" 
                  align="center" 
                  gap={4}
                  style={{ flex: 1, minWidth: '60px' }}
                >
                  <Text variant="caption" weight="bold" color="var(--ggui-color-neutral-500, #6b7280)">
                    {day.day}
                  </Text>
                  <Text style={{ fontSize: '24px' }}>{day.icon}</Text>
                  <Row gap={4} justify="center">
                    <Text variant="caption" weight="bold" color="var(--ggui-color-neutral-900, #111827)">
                      {Math.round(day.high)}°
                    </Text>
                    <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">
                      {Math.round(day.low)}°
                    </Text>
                  </Row>
                </Stack>
              ))}
            </Row>
          </Box>
        </Stack>
      </Card>
    </Box>
  );
}

import React from 'react';
import { Card, Stack, Text } from '@ggui-ai/design/primitives';

interface ForecastDay {
  day: string;
  condition: string;
  high: number;
  low: number;
}

interface Props {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit: string;
  forecast: ForecastDay[];
}

/**
 * WeatherCard Component
 * Displays current weather conditions and a 5-day forecast strip.
 */
export default function WeatherCard({
  city = 'New York',
  temperature = 22,
  condition = 'Sunny',
  humidity = 45,
  windSpeed = 12,
  unit = 'C',
  forecast = [
    { day: 'Mon', condition: 'Sunny', high: 24, low: 18 },
    { day: 'Tue', condition: 'Cloudy', high: 22, low: 16 },
    { day: 'Wed', condition: 'Rainy', high: 19, low: 14 },
    { day: 'Thu', condition: 'Partly Cloudy', high: 21, low: 15 },
    { day: 'Fri', condition: 'Sunny', high: 25, low: 17 },
  ],
}: Props) {

  // Mapping logic for weather icons to maintain visual consistency
  const getWeatherEmoji = (cond: string): string => {
    const c = cond.toLowerCase();
    if (c.includes('sun') || c.includes('clear')) return '☀️';
    if (c.includes('cloud') && c.includes('partly')) return '⛅';
    if (c.includes('cloud')) return '☁️';
    if (c.includes('rain') || c.includes('drizzle')) return '🌧️';
    if (c.includes('storm') || c.includes('thunder')) return '⛈️';
    if (c.includes('snow')) return '❄️';
    if (c.includes('wind')) return '💨';
    return '🌡️';
  };

  return (
    <Card 
      variant="elevated" 
      padding="lg" 
      style={{ 
        maxWidth: '400px',
        width: '100%',
        background: 'var(--ggui-color-surface-container, #ffffff)',
        borderRadius: 'var(--ggui-radius-lg, 16px)',
        transition: 'transform 0.2s ease-in-out',
        cursor: 'default',
        boxShadow: 'var(--ggui-shadow-md, 0 4px 6px rgba(0,0,0,0.1))'
      }}
    >
      <Stack direction="vertical" spacing="lg">
        {/* Top Section: City and Status */}
        <Stack direction="vertical" spacing="xs">
          <Text 
            variant="h2" 
            weight="bold" 
            style={{ 
              color: 'var(--ggui-color-text-primary, #111827)',
              letterSpacing: '-0.025em' 
            }}
          >
            {city}
          </Text>
          <Stack direction="horizontal" spacing="sm" align="center">
            <Text style={{ fontSize: '1.5rem' }}>{getWeatherEmoji(condition)}</Text>
            <Text 
              variant="body" 
              style={{ 
                color: 'var(--ggui-color-text-secondary, #4b5563)',
                textTransform: 'capitalize' 
              }}
            >
              {condition}
            </Text>
          </Stack>
        </Stack>

        {/* Hero Section: Main Temperature */}
        <Stack direction="horizontal" align="start" justify="center">
          <Text 
            style={{ 
              fontSize: 'var(--ggui-font-size-hero, 4.5rem)', 
              fontWeight: 'var(--ggui-font-weight-black, 900)',
              lineHeight: 1,
              letterSpacing: '-0.05em',
              color: 'var(--ggui-color-text-primary, #111827)'
            }}
          >
            {Math.round(temperature)}
          </Text>
          <Text 
            variant="h3" 
            weight="bold" 
            style={{ 
              marginTop: '0.5rem',
              color: 'var(--ggui-color-primary, #2563eb)' 
            }}
          >
            °{unit}
          </Text>
        </Stack>

        {/* Secondary Stats: Humidity and Wind */}
        <Stack 
          direction="horizontal" 
          justify="between" 
          style={{ 
            padding: 'var(--ggui-space-md, 16px)',
            background: 'var(--ggui-color-surface-variant, #f3f4f6)',
            borderRadius: 'var(--ggui-radius-md, 8px)'
          }}
        >
          <Stack direction="vertical" spacing="xxs" align="center">
            <Text 
              variant="caption" 
              style={{ 
                color: 'var(--ggui-color-text-muted, #6b7280)', 
                fontWeight: 'var(--ggui-font-weight-bold, 700)' 
              }}
            >
              HUMIDITY
            </Text>
            <Text variant="body" weight="medium">{humidity}%</Text>
          </Stack>
          <Stack direction="vertical" spacing="xxs" align="center">
            <Text 
              variant="caption" 
              style={{ 
                color: 'var(--ggui-color-text-muted, #6b7280)', 
                fontWeight: 'var(--ggui-font-weight-bold, 700)' 
              }}
            >
              WIND
            </Text>
            <Text variant="body" weight="medium">{windSpeed} km/h</Text>
          </Stack>
        </Stack>

        {/* 5-Day Forecast Grid */}
        <Stack direction="vertical" spacing="md">
          <Stack 
            direction="horizontal" 
            style={{ 
              width: '100%', 
              height: '1px', 
              background: 'var(--ggui-color-border-subtle, #e5e7eb)' 
            }} 
          />
          <Stack 
            direction="horizontal" 
            spacing="sm" 
            justify="between"
            style={{ width: '100%' }}
          >
            {forecast.slice(0, 5).map((day, idx) => (
              <Stack 
                key={day.day + idx} 
                direction="vertical" 
                spacing="xs" 
                align="center"
                style={{ flex: 1 }}
              >
                <Text variant="caption" color="muted">{day.day}</Text>
                <Text style={{ fontSize: '1.25rem' }}>{getWeatherEmoji(day.condition)}</Text>
                <Stack direction="vertical" spacing="none" align="center">
                  <Text variant="caption" weight="bold">{Math.round(day.high)}°</Text>
                  <Text 
                    variant="caption" 
                    color="muted" 
                    style={{ fontSize: '0.65rem' }}
                  >
                    {Math.round(day.low)}°
                  </Text>
                </Stack>
              </Stack>
            ))}
          </Stack>
        </Stack>
      </Stack>
    </Card>
  );
}
